class Solution {
public:
    Solution(int m, int n) {
        total = m * n;
        cnt = total;
    }

    vector<int> flip() {
        int idx = rand() % cnt;
        cnt--;
        int i = idx / n;
        int j = idx % n;
        return {i, j};
    }

    void reset() {
        cnt = total;
    }

private:
    int total;
    int cnt;
};
```
